// 1. Get the raw string from the input (Start node)
const rawString = $('Start').first().json.imgUrls;

// 2. Wrap the string in square brackets to make it a valid JSON array
//    and then parse it into a real JavaScript object.
const parsedData = JSON.parse(`[${rawString}]`);

// 3. Map over the array to create separate items.
//    We extract only the "url" value for each item.
return parsedData.map(item => {
  return {
    json: {
      url: item.image_url.url
    }
  };
});

